import { useEffect } from "react";
import type { ReportPayloadV1 } from "@shared/report-payload";

interface CompletionData {
  payload: ReportPayloadV1;
  redirectUrl: string;
}

function postMessageToParent(type: string, payload?: unknown) {
  window.parent.postMessage(
    {
      type: `redwood:assessment:${type}`,
      payload
    },
    "*"
  );
}

export function useParentCommunication() {
  useEffect(() => {
    postMessageToParent("ready");
    const sendResize = () => {
      const height = Math.max(
        document.body.scrollHeight,
        document.documentElement.scrollHeight
      );
      postMessageToParent("resize", { height });
    };

    sendResize();
    const observer = new ResizeObserver(() => sendResize());
    observer.observe(document.body);
    observer.observe(document.documentElement);

    const interval = window.setInterval(sendResize, 1000);

    return () => {
      observer.disconnect();
      window.clearInterval(interval);
    };
  }, []);

  return {
    notifyComplete(data: CompletionData) {
      postMessageToParent("complete", data);
    }
  };
}
