import { useState, useEffect } from "react";
import { questions, type QuestionAnswers } from "@shared/schema";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { Label } from "@/components/ui/label";
import { Building2, ChevronLeft, ChevronRight } from "lucide-react";

interface QuestionFlowProps {
  onComplete: (answers: QuestionAnswers) => void;
}

export function QuestionFlowScreen({ onComplete }: QuestionFlowProps) {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [answers, setAnswers] = useState<QuestionAnswers>({});

  const currentQuestion = questions[currentIndex];
  const totalQuestions = questions.length;
  const progress = ((currentIndex + 1) / totalQuestions) * 100;
  const currentAnswer = answers[currentQuestion.id];
  const currentAnswerValue = currentAnswer !== undefined ? currentAnswer.toString() : "";
  const hasAnswer = currentAnswer !== undefined;

  const [isAdvancing, setIsAdvancing] = useState(false);

  const handleAnswerAndProceed = (value: string) => {
    const parsedValue = parseInt(value, 10);
    const nextAnswers: QuestionAnswers = {
      ...answers,
      [currentQuestion.id]: parsedValue
    };

    setAnswers(nextAnswers);

    // Let the user see their selection before advancing
    setIsAdvancing(true);
    setTimeout(() => {
      setIsAdvancing(false);
      if (currentIndex < totalQuestions - 1) {
        setCurrentIndex(prev => prev + 1);
      } else {
        onComplete(nextAnswers);
      }
    }, 400);
  };

  const handleNext = () => {
    if (currentIndex < totalQuestions - 1) {
      setCurrentIndex(prev => prev + 1);
    } else if (hasAnswer) {
      onComplete(answers);
    }
  };

  const handlePrevious = () => {
    if (currentIndex > 0) {
      setCurrentIndex(prev => prev - 1);
    }
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === "ArrowRight") {
        e.preventDefault();
        handleNext();
      } else if (e.key === "ArrowLeft") {
        e.preventDefault();
        handlePrevious();
      }
    };

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [currentIndex, hasAnswer]);

  return (
    <div className="min-h-screen app-gradient-bg flex items-center justify-center px-4 py-8 sm:py-12 pb-28 sm:pb-12">
      <div className="w-full max-w-2xl">
        <Card className="border-primary/25 bg-card/45 mb-6 sm:mb-8">
          <CardContent className="pt-5 pb-5 sm:pt-6 sm:pb-6">
            <div className="flex items-start gap-3 sm:gap-4">
              <div className="mt-0.5">
                <Building2 className="w-4 h-4 sm:w-5 sm:h-5 text-primary" />
              </div>
              <div className="min-w-0">
                <h1 className="text-xl sm:text-2xl text-title text-primary leading-tight">
                  Journal entry automation assessment
                </h1>
                <p className="text-sm sm:text-base text-paragraph text-foreground/80 mt-2">
                  How manual journals create control and close risk.
                </p>
              </div>
            </div>

            <div className="mt-5 sm:mt-6">
              <div className="h-1 bg-muted rounded-full overflow-hidden">
                <div
                  className="h-full bg-primary transition-all duration-300 ease-out"
                  style={{ width: `${progress}%` }}
                  data-testid="progress-bar"
                />
              </div>
              <p className="mt-3 text-xs sm:text-sm text-muted-foreground text-paragraph" data-testid="text-question-progress">
                {currentQuestion.category} - {currentIndex + 1} of {totalQuestions} questions completed
              </p>
            </div>
          </CardContent>
        </Card>

        <Card className={`border-card-border mb-8 transition-opacity duration-300 ${isAdvancing ? "opacity-50" : "opacity-100"}`}>
          <CardContent className="pt-6 sm:pt-8 pb-6">
            <h2
              className="text-lg sm:text-xl text-lead text-foreground mb-6 sm:mb-8 leading-relaxed"
              data-testid="text-question"
            >
              {currentQuestion.text}
            </h2>

            <RadioGroup
              key={currentQuestion.id}
              value={currentAnswerValue}
              onValueChange={isAdvancing ? undefined : handleAnswerAndProceed}
              className="space-y-3"
            >
              {currentQuestion.options.map((option, index) => (
                <div
                  key={index}
                  onClick={() => !isAdvancing && handleAnswerAndProceed(index.toString())}
                  className={`flex items-start space-x-3 p-3 sm:p-4 rounded-md border transition-colors cursor-pointer hover-elevate ${
                    currentAnswer === index
                      ? "border-primary bg-accent/30"
                      : "border-card-border bg-card"
                  }`}
                >
                  <RadioGroupItem
                    value={index.toString()}
                    id={`${currentQuestion.id}-option-${index}`}
                    className="mt-0.5 flex-shrink-0"
                    data-testid={`radio-option-${index}`}
                  />
                  <Label
                    htmlFor={`${currentQuestion.id}-option-${index}`}
                    className="text-sm text-foreground leading-relaxed cursor-pointer flex-1 text-paragraph"
                  >
                    {option}
                  </Label>
                </div>
              ))}
            </RadioGroup>
          </CardContent>
        </Card>

        <div className="fixed bottom-0 left-0 right-0 bg-background border-t border-border p-4 flex items-center justify-between gap-3 sm:relative sm:bottom-auto sm:left-auto sm:right-auto sm:bg-transparent sm:border-0 sm:p-0">
          <Button
            variant="ghost"
            onClick={handlePrevious}
            disabled={currentIndex === 0}
            className="text-muted-foreground flex-1 sm:flex-none"
            data-testid="button-previous"
          >
            <ChevronLeft className="w-4 h-4 mr-1" />
            <span className="hidden sm:inline">Previous</span>
          </Button>

          <Button
            onClick={handleNext}
            disabled={!hasAnswer}
            className="flex-1 sm:flex-none"
            data-testid="button-next"
          >
            {currentIndex === totalQuestions - 1 ? "Complete" : "Next"}
            {currentIndex < totalQuestions - 1 && <ChevronRight className="w-4 h-4 ml-1" />}
          </Button>
        </div>
      </div>
    </div>
  );
}
